--&gt;
&lt;blockquote class=&#34;pullquote mindmap mindmap-sm&#34;&gt;&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#serv00-%E6%9C%8D%E5%8A%A1%E6%90%AD%E5%BB%BA%E8%AE%B0%E5%BD%95&#34;&gt;serv00-жңҚеҠЎжҗӯе»әи®°еҪ•&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%9C%8D%E5%8A%A1%E5%99%A8&#34;&gt;жңҚеҠЎеҷЁ&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#login-failed&#34;&gt;login-failed&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%96%87%E4%BB%B6%E5%90%8C%E6%AD%A5&#34;&gt;ж–Үд»¶еҗҢжӯҘ&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E9%87%8D%E5%90%AF%E5%90%8E%E6%9C%8D%E5%8A%A1%E6%81%A2%E5%A4%8D&#34;&gt;йҮҚеҗҜеҗҺжңҚеҠЎжҒўеӨҚ&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#alist-%E5%9B%BE%E5%BA%8A&#34;&gt;alist-еӣҫеәҠ&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%9B%BE%E7%89%87%E4%B8%8B%E8%BD%BD%E9%97%AE%E9%A2%98&#34;&gt;еӣҫзүҮдёӢиҪҪй—®йўҳ&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#cloudflare&#34;&gt;cloudflare&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%80%9F%E7%89%A9%E8%A1%A8&#34;&gt;еҖҹзү©иЎЁ&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;жңҚеҠЎеҷЁ&#34;&gt;жңҚеҠЎеҷЁ&lt;/h2&gt;
&lt;h3 id=&#34;login-failed&#34;&gt;login-failed&lt;/h3&gt;
&lt;p&gt;е®ҳж–№йӮ®д»¶з»ҷзҡ„ең°еқҖ &lt;code&gt;s4.serv00.com&lt;/code&gt; д№ӢеүҚиҝҳиЎҢ, зҺ°еңЁж— жі•зҷ»еҪ•, е…Ёзҗғж— и§ЈжһҗзҠ¶жҖҒ&lt;/p&gt;
&lt;p&gt;ssh host жҚўдёә &lt;code&gt;web4.serv00.com&lt;/code&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;ж–Үд»¶еҗҢжӯҘ&#34;&gt;ж–Үд»¶еҗҢжӯҘ&lt;/h3&gt;
&lt;p&gt;еңЁ duck / rclone / rsync дёӯйҖүжӢ©зҡ„ duck+WebDAV&lt;/p&gt;
&lt;p&gt;е…¶д»–дёӨдёӘдёҚж–№дҫҝ/жңүжҠҘй”ҷ&lt;/p&gt;
&lt;p&gt;жҲ‘зҡ„й…ҚзҪ®: дё»иҰҒз”ЁжқҘеӨҮд»ҪжңҚеҠЎеҷЁдёҠзҡ„еӣҫзүҮж–Үд»¶ &lt;sup id=&#39;cite_ref-1&#39;&gt;&lt;a href=&#34;#cite_note-1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;duck --synchronize davs://pan.weidows.tech/dav/local/ ./backup --username xxx --password xxx --parallel --quiet&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h3 id=&#34;йҮҚеҗҜеҗҺжңҚеҠЎжҒўеӨҚ&#34;&gt;йҮҚеҗҜеҗҺжңҚеҠЎжҒўеӨҚ&lt;/h3&gt;
&lt;p&gt;serv00 жңҚеҠЎеҷЁжҜҸеӨ©дјҡдёҚе®ҡж—¶йҮҚеҗҜ, зҪ‘дёҠжҸҗдҫӣзҡ„ж–№жі•еӨ§еӨҡжҳҜйҮҚеҗҜеҗҺиҝӣдёҖдёӢ cron, дҪҶдјјд№ҺдёҚеӨӘеҘҪз”Ё&lt;/p&gt;
&lt;p&gt;жҲ‘иҮӘе·ұж”№дәҶдёӢ, еҗҜз”Ёе®ҡж—¶ cron:&lt;/p&gt;
&lt;figure class=&#34;highlight gradle&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ps aux | &lt;span class=&#34;keyword&#34;&gt;grep&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;[P]M2&amp;#x27;&lt;/span&gt; || &lt;span class=&#34;regexp&#34;&gt;/home/&lt;/span&gt;Weidows&lt;span class=&#34;regexp&#34;&gt;/.npm-global/&lt;/span&gt;bin/pm2 resurrect&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;еҸҜд»Ҙз”ЁиҝҷдёӘжқҖдёҖдёӢз”ЁжҲ·иҝӣзЁӢ&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pkill -&lt;span class=&#34;built_in&#34;&gt;kill&lt;/span&gt; -u Weidows&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;alist-еӣҫеәҠ&#34;&gt;alist-еӣҫеәҠ&lt;/h2&gt;
&lt;p&gt;жҲ‘зҡ„зӣ®ж ҮжҳҜжҗӯе»әдёҖдёӘ alist , еҗҢж—¶з”Ёжң¬ең°йӮЈ 3 дёӘ G еӯҳеӮЁеҒҡ &lt;code&gt;дёӘдәәеӣҫеәҠ&lt;/code&gt; (зӣёеҪ“еӨҹз”ЁдәҶ, дёҚеӨҹеҶҚеҠ е…¶д»–зӣҳ), зңӢзҪ‘дёҠеҲ«дәәиё©еқ‘зҡ„и®°еҪ•жҢәе°‘зҡ„&lt;/p&gt;
&lt;p&gt;йҰ–е…ҲеңЁ serv00 дёҠжӯЈеёёжҗӯе»әиө·жқҘ, жңүдёӨз§Қж–№жі•иғҪеҜ№еӨ–ејҖж”ҫ: &lt;code&gt;argo cloudflared&lt;/code&gt; жҲ–иҖ… &lt;code&gt;panel ж·»еҠ зҪ‘з«ҷ&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;иҝҳжҳҜжӣҙжҺЁиҚҗзӣҙиҝһ, йҖҹеәҰе’Ңе»¶иҝҹйғҪеҫҲдёҚй”ҷ, argo е№¶дёҚзЁі&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;еӣҫзүҮдёӢиҪҪй—®йўҳ&#34;&gt;еӣҫзүҮдёӢиҪҪй—®йўҳ&lt;/h3&gt;
&lt;p&gt;жҢүдёҠйқўйӮЈж ·жҗӯеҘҪеҗҺ, еңЁзҪ‘йЎөдёӯеӣҫзүҮжҳҫзӨәжІЎжңүй—®йўҳ, дҪҶжҳҜеҸій”® -&amp;gt; ж–°йЎөйқўжү“ејҖеҗҺдјҡзӣҙжҺҘеј№еҲ°дёӢиҪҪ (жҳҜ header и®ҫзҪ®зҡ„й—®йўҳ)&lt;/p&gt;
&lt;p&gt;еҸҜд»ҘдҪҝз”Ё cloudflare зҡ„жңҚеҠЎз»ҷеңЁдёӯй—ҙжҲӘиғЎжӣҙж”№дәҶ:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;cloudflare -&amp;gt; зӮ№ејҖз”Ёзҡ„еҹҹеҗҚ -&amp;gt; и§„еҲҷ -&amp;gt; иҪ¬жҚўи§„еҲҷ -&amp;gt; дҝ®ж”№е“Қеә”еӨҙ&lt;/li&gt;
